import{_ as s,c as a,o as i,b as d}from"./app.6039188d.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 16","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 16","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-07-20T00:00:00.000Z"},"headers":[],"relativePath":"texts/malini-vijayottara/16/index.md"}',n={},c=d('<div class="stanza"><a href="#s16.1" id="s16.1" class="num">16.1</a><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043F\u043E\u0432\u0435\u0434\u0430\u044E \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0433\u0430\u0440\u0432\u0430\u043C\u0430\u0439\u0438 \u0434\u0445\u0430\u0440\u0430\u043D\u0443 (<em>\u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 \u0433\u043E\u0440\u0434\u044B\u043D\u0438</em>), \u043D\u0430\u0438\u043B\u0443\u0447\u0448\u0443\u044E \u0434\u0445\u0430\u0440\u0430\u043D\u0443 \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0438\u0437 \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u0433\u043E\u0440\u0434\u043E\u0441\u0442\u0438 \u0439\u043E\u0433\u0438\u043D\u043E\u0432, \u043E \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0430\u044F \u0439\u043E\u0433\u0438\u043D\u0430\u043C\u0438 .</p></div><div class="stanza"><a href="#s16.2" id="s16.2" class="num">16.2</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E \u043A\u0430\u043A \u0448\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u0438\u043B\u0435\u043F\u0435\u0441\u043A\u043E\u0432\u0443\u044E \u0447\u0430\u043A\u0440\u0443, \u043D\u0435 \u043E\u0442\u043A\u043B\u043E\u043D\u044F\u044F\u0441\u044C \u0443\u043C\u043E\u043C. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F: \xAB\u044D\u0442\u043E \u0435\u0441\u0442\u044C \u042F, \u0432 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0438 (\u043C\u043E\u0438\u0445) \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439\xBB .</p></div><div class="stanza"><a href="#s16.3" id="s16.3" class="num">16.3</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430, \u0439\u043E\u0433\u0438\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u043D\u0435 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D\u044B\u043C \u0435\u0439 (<em>\u0433\u043E\u0440\u0434\u043E\u0441\u0442\u0438</em>), \u0435\u0433\u043E \u043D\u0435\u0440\u0443\u0448\u0438\u043C\u043E\u0435 \xAB\u043C\u043E\u0435\xBB \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0432\u0441\u044E\u0434\u0443 \u0438 \u043D\u0438\u0433\u0434\u0435 .</p></div><div class="stanza"><a href="#s16.4" id="s16.4" class="num">16.4</a><p>\u0412 \u0442\u0430\u043A\u043E\u0439 \u0436\u0435 \u0444\u043E\u0440\u043C\u0435 \u0447\u0430\u043A\u0440\u044B \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0432\u043E\u0439 \u043F\u0443\u043F\u043E\u043A, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F: \xAB\u042F \u0435\u0441\u0442\u044C \u0432\u0441\u0435, \u0432\u043E \u043C\u043D\u0435 \u0432\u0441\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442\xBB .</p></div><div class="stanza"><a href="#s16.5" id="s16.5" class="num">16.5</a><p>\u0422\u043E\u0433\u0434\u0430 \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0430\u0445\u0430\u043C\u043A\u0430\u0440\u044B. \u0427\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u0435\u0439?</p><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u043D\u0435\u0443\u0441\u044B\u043F\u043D\u043E \u0432 \u0441\u0435\u0440\u0434\u0435\u0447\u043D\u043E\u0439 \u0447\u0430\u043A\u0440\u0435 \u041C\u0435\u043D\u044F \u0432 \u0441\u0432\u043E\u0435\u0439 \u0444\u043E\u0440\u043C\u0435;</p></div><div class="stanza"><a href="#s16.6" id="s16.6" class="num">16.6</a><p>\u041E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u043C\u0438\u0440\u0430 \u0441\u043E\u043B\u043D\u0446\u0430, \u0438 \u043F\u043B\u043E\u0434\u0430 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u044D\u0433\u043E. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443, \u0441\u0438\u043D\u0435- \u043A\u0440\u0430\u0441\u043D\u044B\u0439 \u043A\u0440\u0443\u0433 \u0438 \u043F\u0440\u043E\u0447\u0435\u0435;</p></div><div class="stanza"><a href="#s16.7" id="s16.7" class="num">16.7</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0432\u0441\u0435\u0445 \u0434\u0435\u0441\u044F\u0442\u0438 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0439. \u0422\u0430\u043A \u043E\u043F\u0438\u0441\u0430\u043D\u0430 \u0433\u0430\u0440\u0432\u0430\u043C\u0430\u0439\u0438 (\u0434\u0445\u0430\u0440\u0430\u043D\u0430), \u043D\u0430\u0434\u0435\u043B\u044F\u044E\u0449\u0430\u044F \u0434\u043E\u0441\u0442\u043E\u0438\u043D\u0441\u0442\u0432\u043E\u043C \u041F\u0440\u0430\u0434\u0436\u0430\u043F\u0430\u0442\u0438 .</p></div><div class="stanza"><a href="#s16.8" id="s16.8" class="num">16.8</a><p>\u0412 \u0441\u0435\u0440\u0434\u0446\u0435 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442\u0441\u044F \u0432\u043E\u0441\u044C\u043C\u0438\u043B\u0435\u043F\u0435\u0441\u0442\u043A\u043E\u0432\u044B\u0439 (\u043B\u043E\u0442\u043E\u0441), \u043D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0439 \u0434\u0445\u0430\u0440\u043C\u043E\u0439 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430\u043C\u0438 \u0438 \u0432\u0435\u043D\u0447\u0438\u043A\u043E\u043C, \u0441\u0438\u044F\u044E\u0449\u0438\u0439 \u043A\u0430\u043A \u0434\u0438\u0441\u043A \u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E \u0441\u043E\u043B\u043D\u0446\u0430,</p></div><div class="stanza"><a href="#s16.9" id="s16.9" class="num">16.9</a><p>\u0417\u0430 \u043C\u0435\u0441\u044F\u0446 \u0440\u0430\u0437\u0443\u043C \u0441\u0442\u0430\u043D\u0435\u0442 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C, \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 (\u0439\u043E\u0433\u0438\u043D) \u0441\u0442\u0430\u043D\u0435\u0442 \u0434\u0430\u044E\u0449\u0438\u043C \u0448\u0440\u0443\u0442\u0438, \u0437\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u0441\u0430\u043C \u0441\u0442\u0430\u043D\u0435\u0442 \u0430\u0432\u0442\u043E\u0440\u043E\u043C \u0448\u0430\u0441\u0442\u0440 .</p></div><div class="stanza"><a href="#s16.10" id="s16.10" class="num">16.10</a><p>\u0412 \u044D\u0442\u043E\u043C \u043E\u0431\u0440\u0430\u0437\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0435\u0431\u044F, (\u0442\u043E\u0433\u0434\u0430 \u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u0443\u0432\u0438\u0434\u0438\u0442 \u0431\u0443\u0434\u0434\u0445\u0438 \u0442\u0430\u0442\u0442\u0432\u0443, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0431\u0440\u0430\u0445\u043C\u0430\u043D\u0430 \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0437\u043D\u0430\u043D\u0438\u044F \u0418\u0448\u0438 .</p></div><div class="stanza"><a href="#s16.11" id="s16.11" class="num">16.11</a><p>\u0412\u0437\u044B\u0432\u0430\u044F \u043A \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430\u043C (<em>\u0441\u0435\u043C\u044C?- \u0442\u0435\u043A\u0441\u0442 \u043F\u043E\u0432\u0440\u0435\u0436\u0434\u0435\u043D</em>), \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0441\u0430\u043C\u0430\u0434\u0445\u0438 \u043C\u0443\u0434\u0440\u0435\u0446, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435, \u0441\u0442\u0430\u043D\u0435\u0442 \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C, \u0438 \u044F\u0441\u043D\u043E (\u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442) \u0434\u0430\u0436\u0435 \u0442\u043E, \u0447\u0442\u043E \u043D\u0435\u0434\u043E\u0441\u0442\u0438\u0436\u0438\u043C\u043E (\u0434\u043B\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044F) .</p></div><div class="stanza"><a href="#s16.12" id="s16.12" class="num">16.12</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u0432\u0441\u0435 \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0435 \u043F\u0440\u0435\u0436\u0434\u0435, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0434\u0438\u0441\u043A\u0430, (\u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0411\u0440\u0430\u0445\u043C\u044B, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0432 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0438 \u0431\u0443\u0434\u0434\u0445\u0438 .</p></div><div class="stanza"><a href="#s16.13-14" id="s16.13-14" class="num">16.13-14</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 \u0434\u0438\u0441\u043A \u0441\u043E\u043B\u043D\u0446\u0430, \u0430 \u0432\u043D\u0443\u0442\u0440\u0438 \u043D\u0435\u0433\u043E- \u043B\u0443\u043D\u043D\u0443\u044E \u043C\u0430\u043D\u0434\u0430\u043B\u0443, \u0447\u0435\u0440\u0435\u0437 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0442\u0430\u043A\u043E\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u043B\u0435\u0433\u043A\u043E \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0437\u0440\u0435\u043D\u0438\u0435, \u0430 \u0437\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u0443 \u043D\u0435\u0433\u043E \u043F\u043E\u044F\u0432\u044F\u0442\u0441\u044F \u0441\u0438\u0434\u0434\u0445\u0438.</p><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0442\u0430\u043C \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E, \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0442\u0430\u043C \u0431\u043B\u0430\u0433\u043E\u0435 \u0434\u043E\u0441\u0442\u043E\u0438\u043D\u0441\u0442\u0432\u043E \u0438 \u0437\u043D\u0430\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s16.15" id="s16.15" class="num">16.15</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0441\u0438\u044F\u043D\u0438\u0435 \u0432 \u043E\u0431\u0440\u0430\u0437\u0435 \u043B\u0438\u043D\u0433\u0430\u043C\u0430, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u044B \u0418\u0448\u044B. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439, \u043A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435, \u0434\u0438\u0441\u043A (\u0441\u043E\u043B\u043D\u0446\u0430) \u0438 \u0434\u0435\u0441\u044F\u0442\u043A\u0443 \u043F\u0440\u043E\u0447\u0438\u0445, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u0445 \u0438\u0437 \u0434\u0435\u0441\u044F\u0442\u0438;</p></div><div class="stanza"><a href="#s16.16" id="s16.16" class="num">16.16</a><p>\u0414\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u043F\u043B\u043E\u0434\u0430, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0438 (\u0418\u0448\u0438). \u0418\u0445 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0434\u0432\u0430\u0434\u0446\u0430\u0442\u044C \u0447\u0435\u0442\u044B\u0440\u0435, \u0443 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u043F\u044F\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C;</p></div><div class="stanza"><a href="#s16.17" id="s16.17" class="num">16.17</a><p>\u0414\u0445\u0430\u0440\u0430\u043D\u0430 \u0442\u0430\u0442\u0442\u0432, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043A\u0448\u0430\u043C\u044B. \u041F\u0440\u0435\u0434\u043D\u0430\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u044B\u0435 \u0432\u0441\u0435 \u0432\u043C\u0435\u0441\u0442\u0435 \u0434\u043B\u044F \u0431\u043B\u0430\u0433\u0430 \u0439\u043E\u0433\u0438\u043D\u043E\u0432, \u043E\u043D\u0438 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442, \u043F\u043E\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0435 \u043D\u0430 \u0442\u0440\u0438\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0438 \u0448\u0435\u0441\u0442\u044C \u0434\u0440\u0443\u0433\u0438\u0445 .</p></div><div class="stanza"><a href="#s16.18" id="s16.18" class="num">16.18</a><p>\u041E\u043D\u0438 \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u0439\u043E\u0433\u0438\u043D\u0430\u043C\u0438 \u0440\u0430\u0434\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0432 \u0439\u043E\u0433\u0435. \u041E\u0441\u0442\u0430\u0432\u043B\u044F\u044F \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E \u0432 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u043D\u0438 \u0447\u0442\u043E \u0438\u043D\u043E\u0435 \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C;</p></div><div class="stanza"><a href="#s16.19" id="s16.19" class="num">16.19</a><p>(\u041A\u0440\u043E\u043C\u0435) \u0431\u0435\u043B\u043E\u0433\u043E \u043B\u043E\u0442\u043E\u0441\u0430, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0433\u043E \u043D\u0430\u0434 \u0442\u0440\u0435\u043C\u044F \u043C\u0430\u043D\u0434\u0430\u043B\u0430\u043C\u0438. \u0423\u0442\u0432\u0435\u0440\u0434\u0438\u0432\u0438\u0448\u044C \u0432 \u044D\u0442\u043E\u043C (\u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0438 \u0441\u0430\u0434\u0445\u0430\u043A\u0430) \u0437\u0430 \u0442\u0440\u0438 \u043C\u0435\u0441\u044F\u0446\u0430 \u0441\u0442\u0430\u043D\u0435\u0442 \u0437\u043D\u0430\u044E\u0449\u0438\u043C \u0439\u043E\u0433\u0443 .</p></div><div class="stanza"><a href="#s16.20" id="s16.20" class="num">16.20</a><p>\u041E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u043C \u043E\u0442 \u0432\u0441\u0435\u0445 \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439, \u0447\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u0435\u0439? \u0417\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0435\u0449\u0435 \u043D\u0430 \u0437\u0435\u043C\u043B\u0435 \u0443 \u043D\u0435\u0433\u043E \u043F\u043E\u044F\u0432\u0438\u0442\u0441\u044F \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s16.21" id="s16.21" class="num">16.21</a><p>\u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430, \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u0439 \u043E\u0442 \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438 \u0438 \u043F\u0440\u043E\u0447\u0435\u0433\u043E, \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0437\u0440\u044F\u0449\u0438\u043C \u043F\u0443\u0440\u0443\u0448\u0430 \u0442\u0430\u0442\u0442\u0432\u0443. \u0412 \u043B\u043E\u0442\u043E\u0441\u0435 \u043D\u0438\u0436\u0435 \u0441\u0435\u0440\u0434\u0446\u0430, (\u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442\u0441\u044F) \u0442\u0435\u043B\u043E (\u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C) \u0448\u0435\u0441\u0442\u044C \u0430\u043D\u0433\u0443\u043B;</p></div><div class="stanza"><a href="#s16.22" id="s16.22" class="num">16.22</a><p>\u0412 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u043D\u0435\u0433\u043E \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0435\u0431\u044F, (\u0442\u043E\u0433\u0434\u0430 \u0439\u043E\u0433\u0438\u043D ) \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435 \u0441\u0442\u0430\u043D\u0435\u0442 \u043F\u043E\u0431\u0435\u0434\u0438\u0442\u0435\u043B\u0435\u043C \u0441\u043C\u0435\u0440\u0442\u0438. \u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 \u0441 \u0432\u043B\u0430\u0434\u044B\u043A\u043E\u0439 \u043F\u0443\u0440\u0443\u0448\u0430 \u0442\u0430\u0442\u0442\u0432\u044B .</p></div><div class="stanza"><a href="#s16.23" id="s16.23" class="num">16.23</a><p>\u0422\u0430\u043C \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442\u0441\u044F, \u043A\u0430\u043A \u043F\u0440\u0435\u0436\u0434\u0435, \u0434\u0438\u0441\u043A (\u0441\u043E\u043B\u043D\u0446\u0430 ) \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F (\u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u0432 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u0438 \u041F\u0443\u0440\u0443\u0448\u0438 .</p></div><div class="stanza"><a href="#s16.24" id="s16.24" class="num">16.24</a><p>\u042D\u0442\u043E \u043E\u043F\u0438\u0441\u0430\u043D\u043E \u0432\u043A\u0440\u0430\u0442\u0446\u0435 \u0437\u043D\u0430\u043D\u0438\u0435 \u0432\u0435\u0434\u0430\u043D\u0442\u044B, \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u043D\u043E\u0435 \u0440\u0430\u043D\u044C\u0448\u0435 \u041A\u0430\u043F\u0438\u043B\u043E\u0439, \u0438 \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u0435\u043D\u043D\u043E\u0435 \u041C\u043D\u043E\u0439 .</p></div><div class="stanza"><a href="#s16.25" id="s16.25" class="num">16.25</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E \u0446\u0432\u0435\u0442\u0430 \u0442\u0443\u0447\u0438 \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u043E\u0441\u0435\u043D\u0438, \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u043E\u0431\u0440\u0435\u0442\u0435\u0442 (\u0437\u043D\u0430\u043D\u0438\u0435) \u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F \u0438 \u0441\u0442\u0440\u0430\u0441\u0442\u0438, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s16.26" id="s16.26" class="num">16.26</a><p>\u0417\u0430 \u0433\u043E\u0434 \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u044B\u043C \u043E\u0442 \u0441\u0442\u0430\u0440\u043E\u0441\u0442\u0438 \u0441\u043C\u0435\u0440\u0442\u0438, \u0437\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 \u043E\u043D \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0437\u043D\u0430\u043D\u0438\u044F \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0440\u0430\u0433\u0430 (\u0442\u0430\u0442\u0442\u0432\u044B) .</p></div><div class="stanza"><a href="#s16.27-28" id="s16.27-28" class="num">16.27-28</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C (\u0441\u0432\u043E\u0435) \u0442\u0435\u043B\u043E \u043A\u0440\u0430\u0441\u043D\u043E\u0433\u043E \u0446\u0432\u0435\u0442\u0430, \u0446\u0435\u043B\u0438\u043A\u043E\u043C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u043D\u0430\u0434 \u0431\u0440\u043E\u0432\u044F\u043C\u0438, \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0438 \u0448\u0435\u0441\u0442\u0438 \u043C\u0435\u0441\u044F\u0446\u0435\u0432, \u043D\u0435 \u043D\u0430\u043F\u0440\u044F\u0433\u0430\u044F \u0443\u043C, \u0440\u0430\u0434\u0438 \u043F\u0440\u0435\u043E\u0434\u043E\u043B\u0435\u043D\u0438\u044F \u0441\u0442\u0440\u0430\u0441\u0442\u0438 \u0438 \u0432\u043B\u0435\u0447\u0435\u043D\u0438\u044F. \u0417\u0430 \u0433\u043E\u0434 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u044F, \u043E\u043D \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0440\u0430\u0436\u0435\u043D \u0441\u043C\u0435\u0440\u0442\u044C\u044E. \u0417\u0430 \u0442\u0440\u0438 \u0433\u043E\u0434\u0430 (\u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442) \u043F\u043E\u0431\u0435\u0434\u0438\u0442\u0435\u043B\u0435\u043C \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0441 \u0440\u0430\u0433\u0430 (\u0442\u0430\u0442\u0442\u0432\u043E\u0439) .</p></div><div class="stanza"><a href="#s16.29" id="s16.29" class="num">16.29</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u043A\u0440\u0430\u0441\u043D\u043E\u0435 (\u0442\u0435\u043B\u043E) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0432 \u043A\u0440\u0430\u0441\u043D\u043E\u043C \u043B\u043E\u0442\u043E\u0441\u0435 \u043D\u0430\u0434 \u0441\u0435\u0440\u0434\u0446\u0435\u043C \u0441 \u043F\u044F\u0442\u044C\u044E \u0432\u0435\u0442\u0432\u044F\u043C\u0438, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u043F\u043B\u043E\u0434, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0440\u0430\u043D\u044C\u0448\u0435 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 .</p></div><div class="stanza"><a href="#s16.30" id="s16.30" class="num">16.30</a><p>\u041A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u043D\u043E\u0432\u044C \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043E \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0442\u0430\u043C \u0434\u0438\u0441\u043A \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u0442\u043E\u0433\u0434\u0430 \u044F\u0432\u0438\u0442\u0441\u044F, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E, \u043F\u043B\u043E\u0434, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0439 \u0438\u0437 \u043E\u043A\u0440\u0443\u0436\u0435\u043D\u0438\u044F \u0441\u0432\u0435\u0442\u0430 .</p></div><div class="stanza"><a href="#s16.31" id="s16.31" class="num">16.31</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0432 \u0441\u0435\u0440\u0434\u0446\u0435 \u0431\u0435\u043B\u044B\u0439 \u043B\u043E\u0442\u043E\u0441, \u0441 \u0440\u0430\u0441\u043A\u0440\u044B\u0442\u044B\u043C\u0438 \u043B\u0435\u043F\u0435\u0441\u0442\u043A\u0430\u043C\u0438, \u0438 \u0432\u0435\u043D\u0447\u0438\u043A\u043E\u043C, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u044B\u0439 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0430\u043C\u0440\u0438\u0442\u043E\u0439, \u0441 \u043F\u0435\u0441\u0442\u0438\u043A\u043E\u043C, \u0432 \u0432\u0438\u0434\u0435 \u043B\u0443\u043D\u044B .</p></div><div class="stanza"><a href="#s16.33" id="s16.33" class="num">16.33</a><p>\u0422\u043E\u0433\u0434\u0430 \u0443 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0435\u0433\u043E \u0438\u0437 \u044D\u0442\u043E\u0433\u043E \u043B\u043E\u0442\u043E\u0441\u0430 \u0440\u043E\u0434\u044F\u0442\u0441\u044F \u0432\u0441\u0435 \u043F\u043B\u043E\u0434\u044B, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043A\u0430\u043B\u0430 \u043A\u0440\u0430\u043C\u044B .</p></div><div class="stanza"><a href="#s16.34" id="s16.34" class="num">16.34</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u043F\u043E\u0432\u0441\u044E\u0434\u0443 \u0442\u0435\u043B\u043E (\u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C) 4 \u0430\u043D\u0433\u0443\u043B\u044B, \u0438 \u0442.\u0434. \u043A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435, \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0441\u0435\u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0439 (\u043F\u043B\u043E\u0434) \u0438\u0437 \u0432\u0438\u0434\u044C\u044F \u0442\u0430\u0442\u0442\u0432\u044B .</p></div><div class="stanza"><a href="#s16.35" id="s16.35" class="num">16.35</a><p>\u041E\u0442 \u0441\u0435\u0440\u0434\u0446\u0430, \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0438\u0432 \u043D\u0430 \u043F\u043E\u043B-\u0430\u043D\u0433\u0443\u043B\u044B \u043E\u0434\u043D\u0443 \u043D\u0430\u0434 \u0434\u0440\u0443\u0433\u043E\u0439, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E 3 \u0447\u0430\u043A\u0440\u044B, \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443: \u043A\u0440\u0430\u0441\u043D\u0443\u044E, \u0441\u0438\u043D\u044E\u044E \u0438 \u0431\u0435\u043B\u0443\u044E .</p></div><div class="stanza"><a href="#s16.36" id="s16.36" class="num">16.36</a><p>\u0422\u0430\u043C \u043A\u0430\u0436\u0434\u044B\u0439 \u0438\u0437 \u0443\u0437\u043B\u043E\u0432 \u0442\u0438\u0442\u0442\u0445\u0438 \u0435\u0441\u0442\u044C \u043F\u0443\u0440\u0443\u0448\u0430, \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0446\u0432\u0435\u0442\u0430, (\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C), \u043A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \u0434\u0438\u0441\u043A \u0438 \u0442.\u0434. \u0422\u0430\u043A\u043E\u0432\u0430 \u044D\u0442\u0430 \u0432\u0435\u043B\u0438\u043A\u0430\u044F \u0442\u0440\u0438\u0430\u0434\u0430 \u0442\u0430\u0442\u0442\u0432 .</p></div><div class="stanza"><a href="#s16.37" id="s16.37" class="num">16.37</a><p>\u0420\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 13 \u043D\u0430 \u043A\u043E\u043D\u0446\u0435 \u0437\u043D\u0430\u044E\u0442 \u043C\u0443\u0434\u0440\u044B\u0435, \u0422\u0435\u043F\u0435\u0440\u044C \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u044F\u044E\u0442\u0441\u044F \u0434\u0432\u0435 \u0442\u0430\u0442\u0442\u0432\u044B \u2013 \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u043C\u044B\u0435 \u043D\u0430 11 .</p></div><div class="stanza"><a href="#s16.38" id="s16.38" class="num">16.38</a><p>\u0412 \u0447\u0430\u043A\u0440\u0435 \u043E \u043F\u044F\u0442\u0438 \u0441\u043F\u0438\u0446\u0430\u0445, \u043F\u0440\u043E\u0441\u0442\u0438\u0440\u0430\u044E\u0449\u0435\u0439\u0441\u044F \u043E\u0442 \u0433\u043E\u0440\u043B\u0430 \u0434\u043E \u043F\u0443\u043F\u043A\u0430, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u0441\u0435\u0431\u044F, \u0432 \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u0435, \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0439 \u0431\u043B\u0435\u0441\u043A\u0443 \u0433\u043B\u0430\u0437 .</p></div><div class="stanza"><a href="#s16.39" id="s16.39" class="num">16.39</a><p>\u041F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0432\u043E \u0432\u0441\u0435\u0445 \u0430\u0434\u0445\u0432\u0430\u0445, \u043E\u0442 \u0437\u0435\u043C\u043B\u0438 \u0438 \u0434\u043E \u043A\u0430\u043B\u0430 \u0442\u0430\u0442\u0442\u0432\u044B, \u0432\u043B\u0430\u0434\u044B\u043A\u0430 \u0439\u043E\u0433\u0438 \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D (\u0432\u043B\u0438\u044F\u043D\u0438\u044E) \u0432\u0440\u0435\u043C\u0435\u043D\u0438 .</p></div><div class="stanza"><a href="#s16.40" id="s16.40" class="num">16.40</a><p>\u0412 \u0434\u0438\u0441\u043A\u0435 \u0438 \u043F\u0440\u043E\u0447\u0435\u043C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0435, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u043C\u044B\u0435 \u0439\u043E\u0433\u0438\u043D\u0430\u043C\u0438, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0412\u0440\u0435\u043C\u044F \u0438 \u0435\u0433\u043E \u043F\u043B\u043E\u0434</p></div><div class="stanza"><a href="#s16.41" id="s16.41" class="num">16.41</a><p>\u0419\u043E\u0433\u0438\u043D \u0434\u0435\u043B\u0430\u044E\u0449\u0438\u0439 \u0443\u0441\u0442\u043E\u0447\u0438\u0432\u044B\u043C \u0443\u043C \u0432 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u0433\u043E\u0440\u043B\u0430 \u0438\u0437\u043E \u0434\u043D\u044F \u0432 \u0434\u0435\u043D\u044C, \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u043F\u043B\u043E\u0434\u0430 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0441\u0442\u0432\u0430 \u043D\u0430\u0434 \u043C\u0430\u0439\u0435\u0439, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0434\u0438\u0441\u043A\u0435 \u0438 \u0442.\u043F .</p></div><div class="stanza"><a href="#s16.42" id="s16.42" class="num">16.42</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0420\u0430\u0445\u0443, \u0441\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u044E\u0449\u0435\u0433\u043E \u0434\u0438\u0441\u043A \u043B\u0443\u043D\u044B \u0432 \u043E\u0442\u0432\u0435\u0440\u0441\u0442\u0438\u0438 \u0433\u043E\u0440\u043B\u0430, \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u0434\u0432\u0435\u0440\u0436\u0435\u043D \u0432\u043B\u0438\u044F\u043D\u0438\u044E \u043C\u0430\u0439\u0438 .</p></div><div class="stanza"><a href="#s16.43" id="s16.43" class="num">16.43</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0442\u0430\u043C \u0441\u043E\u043B\u043D\u0446\u0435 \u0432 \u043D\u0435\u0431\u0435, \u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0435 (\u0436\u0435\u043C\u0447\u0443\u0436\u0438\u043D\u0435) \u0430 \u0442\u0430\u043A\u0436\u0435 \u0441\u0438\u044F\u044E\u0449\u0435\u0435 \u0442\u0435\u043B\u043E \u0438 \u0442.\u0434. \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u0442 \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0432\u043B\u0430\u0434\u044B\u0447\u0435\u0441\u0442\u0432\u0430,</p></div><div class="stanza"><a href="#s16.44" id="s16.44" class="num">16.44</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043E\u0431\u0440\u0430\u0437 \u043F\u043E\u043B\u0443\u0434\u0435\u043D\u043D\u043E\u0433\u043E (\u0441\u043E\u043B\u043D\u0446\u0430), \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0433\u043E \u0432 \u0437\u0435\u043D\u0438\u0442\u0435, \u043E\u0431\u0440\u0430\u0437 \u0432\u0441\u0435\u0439 \u043C\u0430\u043D\u0442\u0440\u0430 \u0447\u0430\u043A\u0440\u044B, \u0438 \u0435\u0435 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A .</p></div><div class="stanza"><a href="#s16.45" id="s16.45" class="num">16.45</a><p>\u0417\u0430\u0442\u0435\u043C, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043A\u0430\u043B\u0430 \u043A\u0440\u0430\u043C\u0435 \u0439\u043E\u0433\u0438\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u043C\u0430\u043D\u0442\u0440\u044B. \u041F\u043B\u043E\u0434 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F \u0442\u0430\u043C, \u043A\u0430\u043A \u043F\u0440\u0435\u0436\u0434\u0435 \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E, \u043D\u0430\u0434\u0435\u043B\u0438\u0442 \u0435\u0433\u043E \u0432\u0441\u0435\u043C .</p></div><div class="stanza"><a href="#s16.46" id="s16.46" class="num">16.46</a><p>\u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0442\u0430\u043C \u043E\u0431\u0440\u0430\u0437, \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 (\u043F\u0440\u0438\u0440\u043E\u0434\u0443) \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0438. \u0421\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0441\u0432\u0435\u0442, \u0441\u0438\u044F\u044E\u0449\u0438\u0439 \u043D\u0438\u0436\u0435 \u044D\u0442\u043E\u0433\u043E \u043C\u0435\u0441\u0442\u0430, \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u043F\u0430\u0434\u0448\u0438\u043C .</p></div><div class="stanza"><a href="#s16.47" id="s16.47" class="num">16.47</a><p>\u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u044D\u0442\u043E\u0442 \u0441\u0432\u0435\u0442, \u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u0439 \u0438\u0437\u043D\u0443\u0442\u0440\u0438 \u0438 \u0441\u043D\u0430\u0440\u0443\u0436\u0438, \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u043D\u0435 \u0443\u0442\u0435\u0440\u044F\u0435\u0442 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u043C\u0430\u0442\u0440\u0435\u0448\u0432\u0430\u0440\u044B .</p></div><div class="stanza"><a href="#s16.48" id="s16.48" class="num">16.48</a><p>\u041F\u0440\u0438\u043D\u044F\u0432 \u043F\u0430\u0434\u043C\u0430\u0441\u0430\u043D\u0443, \u0439\u043E\u0433\u0438\u043D, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F \u0432\u044B\u0441\u0448\u0443\u044E \u0431\u0438\u0434\u0436\u0443, \u043F\u0443\u0441\u0442\u044C \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043C\u0435\u0436\u0434\u0443 \u0431\u0440\u043E\u0432\u0435\u0439, (\u043D\u0435 \u0433\u043B\u044F\u0434\u044F) \u043D\u0438 \u043D\u0430 \u0447\u0442\u043E \u043F\u0435\u0440\u0435\u0434 \u0441\u043E\u0431\u043E\u0439 .</p></div><div class="stanza"><a href="#s16.49" id="s16.49" class="num">16.49</a><p>\u0417\u0430\u043A\u0440\u044B\u0432 \u0433\u043B\u0430\u0437\u0430, \u0441 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u043E\u0439, \u0431\u0435\u0437 (\u0441\u043B\u0443\u0448\u0430\u043D\u0438\u044F) \u0437\u0432\u0443\u043A\u043E\u0432, \u0438 \u043E\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u043D\u0438\u044F (\u0444\u043E\u0440\u043C) \u043E\u043D \u0443\u0432\u0438\u0434\u0438\u0442 \u0442\u0430\u043C \u043F\u0443\u0440\u0443\u0448\u0443, \u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C 12 \u0430\u043D\u0433\u0443\u043B .</p></div><div class="stanza"><a href="#s16.50" id="s16.50" class="num">16.50</a><p>\u0421\u0434\u0435\u043B\u0430\u0432 \u0443\u043C \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043D\u044B\u043C \u043D\u0430 \u043D\u0435\u043C, \u0431\u043E\u043B\u0435\u0435 \u0442\u0440\u0435\u0445 \u043C\u0435\u0441\u044F\u0446\u0435\u0432, \u0435\u0433\u043E, \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u0441\u0435\u043C\u0438 \u0447\u0430\u0441\u0442\u044F\u043C\u0438 \u0432 \u0444\u043E\u0440\u043C\u0435 \u043D\u0435\u043F\u043E\u0434\u0432\u0438\u0436\u043D\u043E\u0433\u043E \u0441\u0432\u0435\u0442\u0430;</p></div><div class="stanza"><a href="#s16.51" id="s16.51" class="num">16.51</a><p>\u0423\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0433\u043E, \u0446\u0432\u0435\u0442\u0430 \u043B\u0443\u043D\u044B, \u043E\u043D \u0443\u0432\u0438\u0434\u0438\u0442 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0437\u0440\u0435\u043D\u0438\u0435\u043C. \u0423\u0437\u0440\u0435\u0432 \u0442\u043E\u0433\u043E \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u041F\u0443\u0440\u0443\u0448\u0443, \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0437\u043D\u0430\u043D\u0438\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u0438 .</p></div><div class="stanza"><a href="#s16.52" id="s16.52" class="num">16.52</a><p>\u0415\u0441\u043B\u0438 \u043E\u043D \u0431\u0443\u0434\u0435\u0442 \u0431\u0435\u0437 \u0433\u043E\u043B\u043E\u0432\u044B, (\u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0437\u0430 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0441\u043C\u0435\u0440\u0442\u044C \u0432\u043D\u0443\u0442\u0440\u0438 \u0438 \u0441\u043D\u0430\u0440\u0443\u0436\u0438. \u0417\u0430 \u044D\u0442\u043E \u0432\u0440\u0435\u043C\u044F \u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u0439\u043E\u0433\u0443, \u0434\u043E\u043B\u0436\u0435\u043D \u0432\u044B\u043F\u043E\u043B\u043D\u0438\u0442\u044C \u0436\u0435\u043B\u0430\u0435\u043C\u043E\u0435 .</p></div><div class="stanza"><a href="#s16.53" id="s16.53" class="num">16.53</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043D\u0430\u0434 \u0431\u0440\u0430\u0445\u043C\u0430\u0440\u0430\u043D\u0434\u0445\u0440\u043E\u0439 \u0431\u0435\u0437\u0443\u043F\u0440\u0435\u0447\u043D\u044B\u0439 \u0434\u0438\u0441\u043A \u043B\u0443\u043D\u044B, \u0438\u0441\u0442\u043E\u0447\u0430\u044E\u0449\u0438\u0439 \u043F\u043E\u0442\u043E\u043A \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0430\u043C\u0440\u0438\u0442\u044B, \u043D\u0430\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0438\u0439 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0442\u0435\u043B\u043E .</p></div><div class="stanza"><a href="#s16.54" id="s16.54" class="num">16.54</a><p>\u041D\u0430\u043F\u043E\u043B\u043D\u044F\u044F \u0441\u0435\u0431\u044F \u0438\u043C, (\u0441\u043E\u043F\u0440\u043E\u0432\u043E\u0436\u0434\u0430\u0435\u043C\u044B\u0439) \u043E\u0433\u043D\u0435\u043C \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044F (\u0441\u0435\u0431\u044F \u0442\u0430\u043A), \u0441\u043D\u0430\u0440\u0443\u0436\u0438 \u0438 \u0432\u043D\u0443\u0442\u0440\u0438, \u0437\u0430 10 \u0434\u043D\u0435\u0439 \u043E\u043D \u0441\u0442\u0430\u043D\u0435\u0442 \u043F\u043E\u0431\u0435\u0434\u0438\u0442\u0435\u043B\u0435\u043C \u0441\u043C\u0435\u0440\u0442\u0438 .</p></div><div class="stanza"><a href="#s16.55" id="s16.55" class="num">16.55</a><p>\u0420\u0430\u0434\u0438 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u044F \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u0431\u043E\u043B\u0435\u0437\u043D\u0438, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u043E\u0432\u0430\u0442\u044C \u044D\u0442\u0443 \u0439\u043E\u0433\u0443. \u0420\u0430\u0434\u0438 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u044F \u043A\u0430\u0436\u0434\u043E\u0439 \u0431\u043E\u043B\u0435\u0437\u043D\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0442\u044C \u043A\u0430\u0436\u0434\u044B\u0439 \u043E\u0440\u0433\u0430\u043D .</p></div><div class="stanza"><a href="#s16.56" id="s16.56" class="num">16.56</a><p>\u041A\u043E\u0433\u0434\u0430 \u043E\u043D \u0443\u0432\u0438\u0434\u0438\u0442 \u0435\u0433\u043E \u0434\u044B\u043C\u0447\u0430\u0442\u043E\u0433\u043E \u0446\u0432\u0435\u0442\u0430, \u0442\u043E\u0433\u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u0432\u0435\u043B\u0438\u043A\u0430\u044F \u0431\u043E\u043B\u0435\u0437\u043D\u044C, (\u0435\u0441\u043B\u0438 \u043E\u043D \u0431\u0443\u0434\u0435\u0442) \u0447\u0435\u0440\u043D\u044B\u043C, \u0442\u043E \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u0440\u043E\u043A\u0430\u0437\u0443, (\u0435\u0441\u043B\u0438) \u0441\u0438\u043D\u0438\u0439 \u2013 \u0445\u043E\u043B\u043E\u0434\u043E\u0431\u043E\u044F\u0437\u043D\u044C .</p></div><div class="stanza"><a href="#s16.57" id="s16.57" class="num">16.57</a><p>\u0415\u0441\u043B\u0438 \u043E\u043D \u043D\u0435 \u0432\u0438\u0434\u0438\u0442 \u0441\u0432\u043E\u0438\u0445 \u0447\u043B\u0435\u043D\u043E\u0432, \u044D\u0442\u043E \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0435 \u0431\u043E\u043B\u0435\u0437\u043D\u0438. \u0411\u043E\u043B\u0435\u0437\u043D\u044C \u0441\u043B\u0435\u043F\u043E\u0442\u044B, \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043D\u043E\u0441\u0430, \u0438 \u0442.\u0434.;</p></div><div class="stanza"><a href="#s16.58" id="s16.58" class="num">16.58</a><p>\u0423 \u0441\u0435\u0431\u044F \u0438 \u0443 \u0434\u0440\u0443\u0433\u0438\u0445. \u0419\u043E\u0433\u0438\u043D, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u043D\u0430 \u043F\u0443\u0442\u0438 \u0439\u043E\u0433\u0438, \u0437\u0430 \u043F\u044F\u0442\u044C \u043B\u0435\u0442\u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u0442 (\u0437\u043D\u0430\u043D\u0438\u0435) \u0432\u0438\u0434\u044C\u044F \u0442\u0430\u0442\u0442\u0432\u044B, \u043E \u0412\u043B\u0430\u0434\u044B\u0447\u0438\u0446\u0430!</p></div><div class="stanza"><a href="#s16.59" id="s16.59" class="num">16.59</a><p>\u0422\u043E, \u0447\u0442\u043E \u043F\u043E\u0437\u043D\u0430\u0435\u0442 \u0438 \u0432\u043A\u0443\u0448\u0430\u0435\u0442 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E, \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u0438\u043C \u0443\u0442\u0435\u0440\u044F\u043D\u043E, \u0422\u0430\u043C, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u043C\u043E\u043C \u0441\u0438\u044F\u044E\u0449\u0435\u043C (\u0442\u0435\u043B\u0435), \u043E\u043D \u043F\u0440\u0435\u0431\u0443\u0434\u0435\u0442 \u0432\u043E \u0432\u0441\u0435\u0445 \u0442\u0435\u043B\u0430\u0445 .</p></div><div class="stanza"><a href="#s16.60" id="s16.60" class="num">16.60</a><p>\u041E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0432\u0441\u0435, \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0440\u0430\u043D\u0435\u0435, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u044D\u0442\u043E\u0439 \u043A\u0430\u043B\u0430\u043A\u0440\u0430\u043C\u044B. \u0412 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0438 (\u0441\u0432\u0435\u0442\u0430) \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0433\u043E \u0432\u0432\u0435\u0440\u0445\u0443;</p></div><div class="stanza"><a href="#s16.61-62" id="s16.61-62" class="num">16.61-62</a><p>\u041E\u043D (\u043D\u0435 \u0443\u0442\u0435\u0440\u044F\u0435\u0442) \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0432\u0430\u0440\u044B, \u0438 \u043D\u0435 \u0432\u0435\u0440\u043D\u0435\u0442\u0441\u044F \u0432\u043D\u043E\u0432\u044C.\u0422\u0430\u043A, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0449\u0438\u0439 \u0432\u0435\u043B\u0438\u043A\u043E\u0435 \u0441\u0438\u044F\u043D\u0438\u0435 \u0432 \u043E\u0431\u043B\u0430\u0441\u0442\u0438 \u043B\u0431\u0430, \u043E\u043D \u0431\u044B\u0441\u0442\u0440\u043E \u0443\u0432\u0438\u0434\u0438\u0442 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u0432\u043E\u0441\u0435\u043C\u044C \u0446\u0432\u0435\u0442\u043E\u0432. \u0426\u0432\u0435\u0442 \u0442\u0443\u0447\u0438, \u0446\u0432\u0435\u0442 \u0428\u0438\u0442\u0438\u043A\u0430\u043D\u0442\u044B (<em>\u0433\u043E\u0440\u043B\u0430 \u0428\u0438\u0432\u044B</em>);</p></div><div class="stanza"><a href="#s16.63" id="s16.63" class="num">16.63</a><p>\u0426\u0432\u0435\u0442\u0430 \u0440\u0430\u0434\u0436\u0430\u0432\u0430\u0440\u0442\u0430 (<em>\u043B\u044F\u043F\u0438\u0441\u044C-\u043B\u0430\u0437\u0443\u0440\u044C</em>), \u0446\u0432\u0435\u0442\u0430 \u0432\u0430\u0439\u0434\u0443\u0440\u044C\u044F (<em>\u043A\u043E\u0448\u0430\u0447\u0438\u0439 \u0433\u043B\u0430\u0437</em>), \u0446\u0432\u0435\u0442\u0430 \u043F\u0443\u0448\u043F\u0430\u0440\u0430\u0433\u0438 (<em>\u0442\u043E\u043F\u0430\u0437</em>), \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u2013 \u0446\u0432\u0435\u0442 \u043F\u0440\u0430\u0431\u0430\u043B\u0430\u043A\u0438 (<em>\u043A\u043E\u0440\u0430\u043B\u043B</em>) .</p></div><div class="stanza"><a href="#s16.64" id="s16.64" class="num">16.64</a><p>\u0426\u0432\u0435\u0442\u0430 \u043F\u0430\u0434\u043C\u0430\u0440\u0430\u0433\u0438 (<em>\u0440\u043E\u0437\u043E\u0432\u044B\u0439</em>), \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0438\u0439- \u0446\u0432\u0435\u0442 \u043B\u0443\u043D\u044B. \u0423\u0432\u0438\u0434\u0435\u0432 \u044D\u0442\u043E\u0442 \u0432\u044B\u0441\u0448\u0438\u0439 \u0441\u0432\u0435\u0442, \u043E\u043D \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0437\u043D\u0430\u043D\u0438\u0435;</p></div><div class="stanza"><a href="#s16.65" id="s16.65" class="num">16.65</a><p>\u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0432\u0438\u0445\u0430\u0440\u044B \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u0437\u0430\u0442\u0435\u043C \u043D\u0430\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u0412\u0441\u0435. \u041F\u0440\u0438 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0438, \u043F\u0440\u043E\u043D\u0438\u043A\u0430\u044E\u0449\u0438\u043C \u0441\u0432\u0435\u0440\u0445\u0443 \u0438 \u0441\u043D\u0438\u0437\u0443 \u043E\u043D \u043D\u0435 \u0441\u043E\u0439\u0434\u0435\u0442 \u0441 \u044D\u0442\u043E\u0433\u043E \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s16.66" id="s16.66" class="num">16.66</a><p>\u0418\u0442\u0430\u043A \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u044B \u0432\u0441\u0435 \u0440\u0430\u0437\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u044B\u0435 \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u0438. \u0422\u0435\u043F\u0435\u0440\u044C \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u044E \u043E \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0438 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F .</p></div><div class="stanza"><a href="#s16.67" id="s16.67" class="num">16.67</a><p>\u042D\u0442\u0438\u0445 \u043A\u0430\u0447\u0435\u0441\u0442\u0432 \u043D\u0430\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F 8, \u043E\u0442 \u041F\u0438\u0448\u0430\u0447\u0435\u0439, \u0434\u043E \u0430\u043D\u0430\u043D\u0442\u044B. \u0422\u0430\u043A\u043E\u0439 \u0436\u0435 \u0432\u0438\u0434 \u043A\u0430\u0447\u0435\u0441\u0442\u0432. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0443\u043C \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u044B\u043C \u0432 \u0418\u0448\u0435 .</p></div><div class="stanza"><a href="#s16.68" id="s16.68" class="num">16.68</a><p>\u0418\u0442\u0430\u043A, \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u044B \u043E \u043F\u0443\u0442\u0438 \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u044F \u0439\u043E\u0433\u0438\u043D\u0430\u043C\u0438, \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443, \u0432\u043F\u043B\u043E\u0442\u044C \u0434\u043E \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F \u0418\u0448\u0432\u0430\u0440\u044B, \u0440\u0430\u0434\u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0432 \u0439\u043E\u0433\u0435 .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0448\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430</p>',65),p=[c];function l(v,e,t,m,r,f){return i(),a("div",null,p)}var z=s(n,[["render",l]]);export{h as __pageData,z as default};
